$edit=documents_get_dispatch_advice((string)($_GET['edit']??''));$settings=json_load(documents_dispatch_advice_settings_path(),[]);$default="Dear {customer_name},\n\nYour Material Dispatch Advice {dispatch_advice_no} for quotation {quotation_no} is ready.\n\nPlease review the items planned for dispatch before we send them:\n{public_link}\n\nTentative dispatch date: {dispatch_date}\nDelivery location: {delivery_address}\n\nPlease contact us before dispatch if any clarification is needed.\n\nRegards,\n{company_name}\n{company_phone}";?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>Dispatch Advices</title><link rel="stylesheet" href="assets/css/admin-unified.css"></head><body class="admin-shell commercial-admin"><main class="commercial-shell"><header class="card commercial-header"><div><p class="admin-kicker">Commercial workspace</p><h1>Material Dispatch Advice</h1><p>Prepare a customer-safe planned dispatch list before issuing the Challan.</p></div><nav class="commercial-header__actions"><a class="btn secondary" href="admin-dashboard.php">Dashboard</a><a class="btn secondary" href="admin-documents.php">Document Center</a></nav></header><?= render_commercial_lifecycle('dispatch_advice') ?><?php if(isset($_GET['message'])):?><div class="card"><?=htmlspecialchars((string)$_GET['message'])?></div><?php endif;?>
<?php if($edit):$locked=$edit['status']!=='draft';$shareMobile=documents_dispatch_advice_customer_mobile($edit,documents_get_quote((string)$edit['quotation_id'])??[]);$shareEligible=in_array($edit['status'],['finalized','shared','acknowledged','customer_accepted'],true);?><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($_SESSION['csrf_token']??'')?>"><input type="hidden" name="id" value="<?=htmlspecialchars($edit['id'])?>"><section class="form-section-card"><h2><?=htmlspecialchars($edit['dispatch_advice_no'])?> <span class="status-badge"><?=htmlspecialchars($edit['status'])?></span></h2><p>Quotation: <?=htmlspecialchars($edit['quotation_no'])?> · Agreement: <?=htmlspecialchars($edit['agreement_no'])?> · Customer: <?=htmlspecialchars($edit['customer_name'])?> / <?=htmlspecialchars($edit['customer_mobile'])?></p><div class="form-grid"><div><label>Planned dispatch date</label><input type="date" name="planned_dispatch_date" value="<?=htmlspecialchars($edit['planned_dispatch_date'])?>" <?=$locked?'disabled':''?>></div><div><label>Delivery address</label><textarea name="delivery_address" <?=$locked?'disabled':''?>><?=htmlspecialchars($edit['delivery_address'])?></textarea></div></div></section><section class="form-section-card"><h3>Customer-safe items</h3><table><thead><tr><th>Name</th><th>Description</th><th>Brand/model</th><th>Qty</th><th>Unit</th><th>Remarks</th></tr></thead><tbody><?php if(empty($edit['items'])):?><tr class="js-empty-items"><td colspan="6"><strong>No items added yet.</strong><br>Click + Add Item to choose the materials planned for dispatch.</td></tr><?php endif;?><?php foreach($edit['items'] as $r):?><tr><?php foreach(['name','description','brand_model','qty','unit','remarks'] as $k):?><td><input name="<?=$k?>[]" value="<?=htmlspecialchars((string)$r[$k])?>" <?=$locked?'disabled':''?>></td><?php endforeach;?><input type="hidden" name="catalog_item_id[]" value="<?=htmlspecialchars((string)($r['catalog_item_id']??''))?>"><input type="hidden" name="line_id[]" value="<?=htmlspecialchars((string)($r['line_id']??''))?>"></tr><?php endforeach;?></tbody></table><?php if(!$locked):?><details class="item-picker"><summary class="btn secondary">+ Add Item</summary><div class="card"><?php foreach($catalog as $ci):if(empty($ci['active']))continue;?><button type="button" class="btn secondary js-add-catalog-item" data-item="<?=htmlspecialchars(json_encode($ci),ENT_QUOTES,'UTF-8')?>">+ <?=htmlspecialchars($ci['name'])?></button><?php endforeach;?><hr><button type="button" class="btn secondary" id="create-generic-item">+ Create New Generic Item</button></div></details><?php endif;?><label>Customer note</label><textarea name="customer_note" <?=$locked?'disabled':''?>><?=htmlspecialchars($edit['customer_note'])?></textarea></section><p><?php if(!$locked):?><button class="btn" name="action" value="save">Save draft</button> <button class="btn" name="action" value="finalize">Finalize</button><?php else:?><button class="btn" name="action" value="revision">Create revision</button><?php endif;?> <a class="btn secondary" href="dispatch-advice-view.php?id=<?=urlencode($edit['id'])?>" target="_blank">View / Print HTML</a> <button class="btn secondary" name="action" value="share_toggle"><?= $edit['public_share_enabled']?'Disable':'Enable'?> public link</button><?php if($edit['public_share_enabled']):?><a class="btn secondary" href="dispatch-advice-public.php?token=<?=urlencode($edit['public_token'])?>" target="_blank">Copy/open public link</a><?php endif;?><button class="btn secondary" name="action" value="share_whatsapp" formtarget="_blank" <?=(!$shareEligible||$shareMobile==='')?'disabled':''?>>Share</button><?php if(!$shareEligible):?><small>Finalize this Dispatch Advice before sharing.</small><?php elseif($shareMobile===''):?><small>Customer mobile is missing or invalid.</small><?php endif;?> <button class="btn danger" name="action" value="cancel">Cancel</button> <button class="btn secondary" name="action" value="archive">Archive</button></p></form><?php else:?><section class="card"><h2>Create from quotation / packing list</h2><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($_SESSION['csrf_token']??'')?>"><select name="quotation_id"><?php foreach($quotes as $q):?><option value="<?=htmlspecialchars($q['id'])?>"><?=htmlspecialchars(($q['quote_no']??'').' | '.($q['customer_name']??''))?></option><?php endforeach;?></select><button class="btn" name="action" value="create">Create Dispatch Advice</button></form></section><section class="card"><h2>Dispatch Advices</h2><nav class="commercial-flow-strip"><a href="?tab=active" class="<?=$tab==='active'?'active':''?>">Active</a><a href="?tab=drafts" class="<?=$tab==='drafts'?'active':''?>">Drafts</a><a href="?tab=customer_accepted" class="<?=$tab==='customer_accepted'?'active':''?>">Customer Accepted</a><a href="?tab=archived_cancelled" class="<?=$tab==='archived_cancelled'?'active':''?>">Archived / Cancelled</a></nav><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($_SESSION['csrf_token']??'')?>"><div class="commercial-toolbar"><label><input type="checkbox" onclick="document.querySelectorAll('.js-bulk-da').forEach(c=>c.checked=this.checked)"> Select all</label><select name="bulk_action"><option value="archive">Archive</option><option value="cancel">Cancel</option><option value="restore">Restore</option></select><input name="bulk_reason" placeholder="Reason for cancel"><button class="btn secondary" name="action" value="bulk_transition">Apply bulk action</button></div><table><tr><th></th><th>Number</th><th>Customer</th><th>Status</th><th>Action</th></tr><?php foreach($advices as $d):?><tr><td><input class="js-bulk-da" type="checkbox" name="selected_ids[]" value="<?=htmlspecialchars((string)$d['id'])?>"></td><td><?=htmlspecialchars($d['dispatch_advice_no'])?></td><td><?=htmlspecialchars($d['customer_name'])?></td><td><?=htmlspecialchars($d['status'])?></td><td><a class="btn" href="?edit=<?=urlencode($d['id'])?>">Open</a></td></tr><?php endforeach;?></table></form></section><section class="card"><h2>Generic item catalog</h2><p>Seeded customer-facing items and reusable additions.</p><table><tr><th>Item</th><th>Unit</th></tr><?php foreach($catalog as $ci): if(empty($ci['active'])) continue;?><tr><td><?=htmlspecialchars($ci['name'])?></td><td><?=htmlspecialchars($ci['default_unit'])?></td></tr><?php endforeach;?></table><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($_SESSION['csrf_token']??'')?>"><input name="catalog_name" placeholder="+ Add item" required><input name="catalog_unit" value="Nos" required><button class="btn" name="action" value="catalog_add">Add item</button></form></section><section class="card"><h2>WhatsApp template</h2><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($_SESSION['csrf_token']??'')?>"><textarea name="whatsapp_template" rows="12"><?=htmlspecialchars($settings['whatsapp_template']??$default)?></textarea><p>{customer_name}, {customer_mobile_mask}, {dispatch_advice_no}, {dispatch_advice_version}, {quotation_no}, {agreement_no}, {dispatch_date}, {delivery_address}, {item_count}, {item_summary}, {acceptance_ref}, {confirmed_at}, {public_link}, {company_name}, {company_phone}, {company_whatsapp}</p><button class="btn" name="action" value="save_template">Save template</button><p>Preview resolves when a customer confirms. Any unsupported <code>{placeholder}</code> remains visible in the message as a warning.</p></form></section><?php endif;?></main><script>document.addEventListener('DOMContentLoaded',()=>{const tbody=document.querySelector('form tbody');if(!tbody)return;const add=item=>{const existing=[...tbody.querySelectorAll('input[name="catalog_item_id[]"]')].some(x=>x.value===item.id);if(existing&&!confirm(item.name+' is already listed. Add another identical line?'))return;const row=document.createElement('tr');const values=[item.name,item.default_description||'',item.default_brand_model||'',1,item.default_unit||'Nos',''];values.forEach((value,index)=>{const td=document.createElement('td'),input=document.createElement('input');input.name=['name[]','description[]','brand_model[]','qty[]','unit[]','remarks[]'][index];input.value=value;td.appendChild(input);row.appendChild(td)});[['catalog_item_id[]',item.id],['line_id[]','']].forEach(([name,value])=>{const input=document.createElement('input');input.type='hidden';input.name=name;input.value=value;row.appendChild(input)});tbody.querySelector('.js-empty-items')?.remove();tbody.appendChild(row);row.querySelector('input[name=\"qty[]\"]')?.focus()};document.querySelectorAll('.js-add-catalog-item').forEach(button=>button.addEventListener('click',()=>add(JSON.parse(button.dataset.item))));document.getElementById('create-generic-item')?.addEventListener('click',()=>{const name=prompt('Generic item name');if(!name)return;const unit=prompt('Default unit','Nos')||'Nos';const form=document.querySelector('form');[['action','catalog_create_for_advice'],['catalog_name',name],['catalog_unit',unit]].forEach(([key,value])=>{const input=document.createElement('input');input.type='hidden';input.name=key;input.value=value;form.appendChild(input)});form.submit()})});</script></body></html>
